import React from "react";
import IssuerDashboard from "../components/issuer/IssuerDashboard";

export default function IssuerPortal() {
  return (
    <div className="page">
      <h1>Issuer Portal</h1>
      <p className="muted">
        KYC providers (banks, exchanges) approve or revoke reusable KYC
        credentials for user wallets.
      </p>
      <div className="grid">
        <IssuerDashboard />
      </div>
    </div>
  );
}
